RuleSet.GenRule:
# # Initialize locals # orahost="" oraport="" orapwd="" oraservice="" orauser="" logfilename="" parmerrors="" TK_DUALCASE_IN_CASE_STATEMENTS=true
# # Parse the command line options # while [ -n "$$1" ] do case "$$1" in
-L) shift logfilename=$$1 shift ;;
-H) shift orahost=$$1 shift ;;
-P) shift orapwd=$$1 shift ;;
-p) shift oraport=$$1 shift ;;
-S) shift oraservice=$$1 shift ;;
-U) shift orauser=$$1 shift ;;
*) echo >&2 "ERROR: Option $$1 not recognized." parmerrors="Y" shift ;; esac done
